// 1. 从上游节点读取字段“分行后故事”
const rawText = items[0].json['分行后故事'] || '';

// 2. 切成 [段落, 分隔符, 段落, 分隔符, ...] 的交替数组
const parts = rawText.split(/(\n{2,})/);

// 3. 定义“长段”阈值
const LONG_THRESHOLD = 50;

// 4. 遍历交替数组，去重长段
const seen = new Map();   // key: 段落内容
const keepParts = [];     // 要保留的段落或分隔符

for (let i = 0; i < parts.length; i++) {
  const chunk = parts[i];
  // 分隔符直接保留
  if (/^\n{2,}$/.test(chunk)) {
    keepParts.push(chunk);
    continue;
  }
  // 段落
  const t = chunk.trim();
  if (t.length < LONG_THRESHOLD) {
    // 短段直接保留
    keepParts.push(chunk);
  } else {
    // 长段只保留第一次
    if (!seen.has(t)) {
      seen.set(t, true);
      keepParts.push(chunk);
    }
    // 重复长段直接丢弃
  }
}

// 5. 拼回完整文本
const out = keepParts.join('');

// 6. 向下游输出字段“删除重段后故事”
return [{ json: { '删除重段后故事': out } }];

// n8n Code 节点 － Run Once for All Items
// 上游字段：清洗后故事
// 下游字段：分行后故事

const src = items[0].json['整合后故事'] || '';

// 把“已换行却无空行”的地方再补一个 \n，让它成为 Markdown 的新段落
const out = src.replace(/([^\n])\n([^\n])/g, '$1\n\n$2');

items[0].json['分行后故事'] = out;
return items;

// 'items' 是 n8n 提供的包含所有输入数据的数组
// 我们将遍历每个传入的项目
const outputItems = [];

for (const item of items) {
  try {
    // 1. 从当前项的 json 数据中获取 "名字库" 字段的内容
    // item.json.名字库
    const namesString = item.json.名字库;

    // 2. 检查字段是否存在且为非空字符串
    if (!namesString || typeof namesString !== 'string' || namesString.trim() === '') {
      // 如果 "名字库" 字段无效，则在 item 中添加一个错误信息，然后继续处理下一项
      item.json.error = "未找到有效的'名字库'字段，或该字段为空。";
      outputItems.push(item);
      continue;
    }

    // 3. 使用顿号 '、' 将字符串分割成一个名字数组
    const namesArray = namesString.split('、');

    // 4. 获取数组的长度
    const arrayLength = namesArray.length;

    // 5. 生成一个 0 到 (数组长度 - 1) 之间的随机整数索引
    const randomIndex = Math.floor(Math.random() * arrayLength);

    // 6. 使用随机索引从数组中获取一个名字
    const randomName = namesArray[randomIndex];

    // 7. 将选中的名字添加(或覆盖)到 item.json 的 'selectedName' 字段中
    // 这样做会保留所有来自上一个节点的原始数据，并只添加新字段
    item.json.selectedName = randomName;

    // 8. 将修改后的 item 添加到输出数组中
    outputItems.push(item);

  } catch (error) {
    // 捕获任何可能的错误（例如 item.json 不存在）
    if (item.json) {
      item.json.error = error.message;
    }
    outputItems.push(item);
  }
}

// 9. 返回所有处理过的 items
return outputItems;

// 从指定的上游节点 '编辑参数-选择标题输入2' 获取数据
// 这确保了无论有多少个节点连接到此节点，我们都只从目标节点读取数据
const inputData = $('编辑参数-选择标题输入2').first().json;

// 用户指定的字段是 '引言库'
const fieldName = '引言库';
let inputString = inputData[fieldName];

// 增加健壮性：如果 '引言库' 字段不存在，尝试 's引言库' (根据你示例中的可能笔误)
if (!inputString && inputData['s引言库']) {
  inputString = inputData['s引言库'];
}

// 检查输入是否有效
if (!inputString || typeof inputString !== 'string') {
  // 如果输入为空或不是字符串，返回一个空字符串或默认值，以避免后续节点出错
  return [{
    randomQuote: '' // 或者可以返回一个默认的引言，例如：randomQuote: '暂无引言。'
  }];
}

// 使用 '---' 作为分隔符，将长字符串分割成一个引言数组
// .map(item => item.trim()) 会在分割后立即清理每个元素首尾的空白字符
const quotesArray = inputString.split('---').map(quote => quote.trim());

// 过滤掉可能因分割产生的空字符串（例如，如果输入以'---'开头或结尾）
const validQuotes = quotesArray.filter(quote => quote.length > 0);

// 如果过滤后数组为空，说明输入内容只有分隔符，返回空字符串
if (validQuotes.length === 0) {
  return [{
    randomQuote: ''
  }];
}

// 生成一个随机索引，范围从 0 到 (数组长度 - 1)
const randomIndex = Math.floor(Math.random() * validQuotes.length);

// 根据随机索引从数组中挑选一个引言
const selectedQuote = validQuotes[randomIndex];

// n8n 的 Code 节点需要返回一个对象数组
// 我们将挑选出的引言放在 'randomQuote' 字段中，以便下一个节点使用
return [{
  randomQuote: selectedQuote
}];

// 从上游节点获取输入数据
// 'items' 是 n8n 传入的数据数组，我们处理第一个元素 (items[0])
const inputData = items[0].json;

// 检查 '地点库' 字段是否存在且不为空
if (!inputData['地点库'] || inputData['地点库'].trim() === '') {
  // 如果输入无效，可以返回一个空值或一个错误信息
  // 这里我们返回一个带有空字符串的字段，方便下游节点处理
  return [{
    json: {
      randomLocation: '',
      error: '输入的地点库为空或不存在'
    }
  }];
}

// 获取地点字符串
const locationString = inputData['地点库'];

// 使用中文顿号 '、' 将字符串分割成一个数组
// 使用 .map() 清理每个地点名周围可能存在的空格
const locationsArray = locationString.split('、').map(loc => loc.trim());

// 从数组中随机选择一个地点
// 1. 生成一个 0 到 1 之间的随机数
// 2. 乘以数组长度得到一个 0 到 length 之间的随机浮点数
// 3. 使用 Math.floor() 向下取整，得到一个有效的数组索引
const randomIndex = Math.floor(Math.random() * locationsArray.length);
const selectedLocation = locationsArray[randomIndex];

// n8n 的 Code 节点需要返回一个对象数组
// 我们将结果放在 'randomLocation' 字段中，方便下游节点引用
return [{
  json: {
    randomLocation: selectedLocation
  }
}];

// ✅ 最终修复版：直接提取有效数据，忽略语法错误
const sourceData = $('Gemini 2.5 pro-生图数组生成').first().json.message.content;

if (!sourceData) {
  throw new Error("❌ 无法读取 message.content 字段");
}

// 1. 清理Markdown标记
const cleanString = sourceData
  .replace(/^```json\s*/, '')
  .replace(/\s*```$/, '')
  .trim();

// 2. 直接提取所有Chapter对象（无视外层JSON结构）
const chapterMatches = cleanString.matchAll(/\{\s*"Chapter":\s*"(\d+)",\s*"Prompt content":\s*"[\s\S]*?"\s*\}/g);

const chapters = [];
for (const match of chapterMatches) {
  try {
    chapters.push(JSON.parse(match[0]));
  } catch (e) {
    console.warn(`⚠️ 跳过无效章节: ${e.message}`);
  }
}

// 3. 按章节号排序
chapters.sort((a, b) => parseInt(a.Chapter) - parseInt(b.Chapter));

if (chapters.length === 0) {
  throw new Error("❌ 未找到任何有效章节数据");
}

// 4. 返回n8n格式
return chapters.map(item => ({ json: item }));

// 获取数据
const imageArray = $("Aggregate").first().json["图片"]; // 使用first()获取第一个元素
const article = $input.first().json['清洗后故事'];

// 验证数据格式
if (!Array.isArray(imageArray) || typeof article !== 'string') {
  throw new Error(`数据格式错误: 图片类型=${typeof imageArray}, 文章类型=${typeof article}`);
}

// 构建图片映射对象
const imageMap = {};
imageArray.forEach(item => {
  // 处理字符串格式 "00：url"
  if (typeof item === 'string') {
    const parts = item.split('：').map(s => s.trim());
    if (parts.length >= 2) {
      const key = parts[0];
      const url = parts[1];
      if (key && url) {
        imageMap[key] = url;
      }
    }
  }
});

// 替换文章中的占位符
const result = article.replace(/<--(\d{2})-->/g, (match, key) => {
  const url = imageMap[key];
  return url ? `![](${url})` : match;
});

// 返回结果
return [{ json: { text: result } }];

// ===== 调试：打印上游数据实际结构 =====
console.log("上游节点原始数据:", JSON.stringify(items, null, 2));

// ===== 安全地提取图片链接 =====
let imageUrls = [];

// 情况1：如果上游数据在 items[0].json 中（数组格式）
if (Array.isArray(items[0]?.json)) {
  const upstreamData = items[0].json;

  // 尝试从每个item的 .data[] 中提取
  upstreamData.forEach((item, idx) => {
    if (item?.data && Array.isArray(item.data)) {
      item.data.forEach(img => {
        if (img?.url) imageUrls.push(img.url.trim());
      });
    }
    // 情况2：如果直接是 .url 字段
    else if (item?.url) {
      imageUrls.push(item.url.trim());
    }
  });
}

// 情况3：如果数据直接在当前items中
else {
  items.forEach(item => {
    if (item?.json?.url) {
      imageUrls.push(item.json.url.trim());
    }
    if (item?.json?.data && Array.isArray(item.json.data)) {
      item.json.data.forEach(img => {
        if (img?.url) imageUrls.push(img.url.trim());
      });
    }
  });
}

// ===== 打印提取到的链接（调试用） =====
console.log("提取到的图片链接:", imageUrls);

// ===== 处理逻辑：交替取图 =====
const result = [];
const totalNeeded = 7;
const imagesPerSet = 4;

// 将链接分为两组（假设前两组交替）
for (let i = 0; i < imagesPerSet && result.length < totalNeeded; i++) {
  // 第一组第i张
  if (i < imagesPerSet && imageUrls[i]) {
    result.push({
      "图片": `${String(result.length).padStart(2, '0')}：${imageUrls[i]}`
    });
  }

  // 第二组第i张
  const secondIdx = i + imagesPerSet;
  if (result.length < totalNeeded && imageUrls[secondIdx]) {
    result.push({
      "图片": `${String(result.length).padStart(2, '0')}：${imageUrls[secondIdx]}`
    });
  }
}

// ===== 返回结果 =====
return result.map(item => ({ json: item }));

// 白名单：保留字符（中文汉字、阿拉伯数字、换行/空格、Markdown符号、常见标点）
// 说明：已剔除单引号，中文省略号…和英文省略号...将被额外处理
// $input.first().json.choices[0].message.content || ''
// $input.first().json.text
const reg = /[^-\u4E00-\u9FFF0-9\s*#_>\[\]`()，。！？；：“”、（）.<]/g;

return items.map(item => {
  const raw = $input.first().json.text  || '';
  // 第一步：剔除不在白名单中的字符
  // 第二步：剔除中文省略号（……）和英文省略号（...）
  const cleaned = raw.replace(reg, '').replace(/…+/g, '').replace(/\.{3,}/g, '');
  return { json: { '清洗后故事': cleaned } };
});

// 获取上游输入的文本
const inputText = $input.first().json.text;

// 使用正则表达式匹配形如 <--00-->、<--01--> 的占位符
// 模式解释：
// \<-- 匹配开头的 <--
// \d+ 匹配一个或多个数字
// --\> 匹配结尾的 -->
// g 标志表示全局匹配（替换所有出现的）
const placeholderPattern = /<--\d+-->/g;

// 删除所有匹配的占位符，如果没有匹配项则返回原文
const cleanedText = inputText.replace(placeholderPattern, '');

// 输出结果给下游
return [{ json: { text: cleanedText } }];
